import { useState, useRef } from "react";
import { Link } from "react-router-dom";
import { motion, useInView, AnimatePresence } from "framer-motion";
import { properties } from "../../../mocks/properties";

function PropertyCard({ property, index }: { property: typeof properties[0]; index: number }) {
  const [hovered, setHovered] = useState(false);
  const ref = useRef(null);
  const inView = useInView(ref, { once: true, margin: "-50px" });

  return (
    <motion.div
      ref={ref}
      className="bg-white rounded-2xl overflow-hidden group cursor-pointer"
      initial={{ opacity: 0, y: 50 }}
      animate={inView ? { opacity: 1, y: 0 } : {}}
      transition={{ duration: 0.6, delay: index * 0.1 }}
      whileHover={{ y: -8 }}
      onHoverStart={() => setHovered(true)}
      onHoverEnd={() => setHovered(false)}
    >
      <div className="relative h-52 overflow-hidden">
        <motion.img
          src={property.image}
          alt={property.title}
          className="w-full h-full object-cover object-top"
          animate={{ scale: hovered ? 1.08 : 1 }}
          transition={{ duration: 0.6 }}
        />
        <AnimatePresence>
          {hovered && (
            <motion.div
              className="absolute inset-0 flex items-center justify-center bg-black/30"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
            >
              <motion.div
                className="flex items-center gap-2 px-4 py-2 bg-[#C9A84C] text-white text-xs font-semibold rounded-full"
                initial={{ scale: 0.8 }}
                animate={{ scale: 1 }}
              >
                <i className="ri-flight-takeoff-line" />
                Drone View
              </motion.div>
            </motion.div>
          )}
        </AnimatePresence>
        <div className="absolute top-3 left-3">
          <span className="px-3 py-1 bg-[#C9A84C] text-white text-xs font-semibold rounded-full">
            {property.tag}
          </span>
        </div>
        <div className="absolute top-3 right-3">
          <span className="px-3 py-1 bg-black/40 backdrop-blur-sm text-white text-xs rounded-full">
            {property.type}
          </span>
        </div>
      </div>

      <div className="p-5">
        <h3 className="font-bold text-[#1C1C1C] text-base mb-1">{property.title}</h3>
        <div className="flex items-center gap-1.5 mb-3">
          <div className="w-4 h-4 flex items-center justify-center">
            <i className="ri-map-pin-line text-[#C9A84C] text-xs" />
          </div>
          <span className="text-[#888] text-xs">{property.location}</span>
        </div>

        <div className="flex items-center gap-4 pb-4 border-b border-[#F0EDE8] text-[#888]">
          <span className="flex items-center gap-1.5 text-xs">
            <div className="w-4 h-4 flex items-center justify-center">
              <i className="ri-hotel-bed-line text-xs" />
            </div>
            {property.bedrooms} Beds
          </span>
          <span className="flex items-center gap-1.5 text-xs">
            <div className="w-4 h-4 flex items-center justify-center">
              <i className="ri-drop-line text-xs" />
            </div>
            {property.bathrooms} Baths
          </span>
          <span className="flex items-center gap-1.5 text-xs">
            <div className="w-4 h-4 flex items-center justify-center">
              <i className="ri-ruler-line text-xs" />
            </div>
            {property.area.toLocaleString()} sqft
          </span>
        </div>

        <div className="pt-4 flex items-center justify-between">
          <span className="text-[#1C1C1C] font-bold text-lg" style={{ fontFamily: "'Cormorant Garant', serif" }}>
            {property.price}
          </span>
          <motion.button
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            className="flex items-center gap-1.5 text-[#C9A84C] text-xs font-semibold cursor-pointer whitespace-nowrap"
          >
            View Details
            <div className="w-4 h-4 flex items-center justify-center">
              <i className="ri-arrow-right-line text-xs" />
            </div>
          </motion.button>
        </div>
      </div>
    </motion.div>
  );
}

export default function FeaturedListings() {
  const [filter, setFilter] = useState("All");
  const types = ["All", "Villa", "Estate", "Penthouse", "Beachfront", "Modern Home"];

  const filtered = filter === "All" ? properties : properties.filter(p => p.type === filter);

  const ref = useRef(null);
  const inView = useInView(ref, { once: true, margin: "-100px" });

  return (
    <section ref={ref} className="py-24 bg-white">
      <div className="max-w-7xl mx-auto px-6 lg:px-10">
        <motion.div
          className="flex flex-col md:flex-row md:items-end justify-between mb-12 gap-6"
          initial={{ opacity: 0, y: 30 }}
          animate={inView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.7 }}
        >
          <div>
            <span className="text-[#C9A84C] text-xs font-semibold tracking-widest uppercase">Premium Listings</span>
            <h2 className="text-4xl lg:text-5xl font-bold text-[#1C1C1C] mt-2" style={{ fontFamily: "'Cormorant Garant', serif" }}>
              Featured Properties
            </h2>
          </div>
          <Link
            to="/map"
            className="flex items-center gap-2 text-[#1C1C1C] text-sm font-medium hover:text-[#C9A84C] transition-colors cursor-pointer whitespace-nowrap"
          >
            View All Listings
            <div className="w-5 h-5 flex items-center justify-center">
              <i className="ri-arrow-right-line" />
            </div>
          </Link>
        </motion.div>

        <motion.div
          className="flex items-center gap-2 mb-8 overflow-x-auto pb-2"
          initial={{ opacity: 0 }}
          animate={inView ? { opacity: 1 } : {}}
          transition={{ duration: 0.7, delay: 0.2 }}
        >
          {types.map((type) => (
            <button
              key={type}
              onClick={() => setFilter(type)}
              className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap cursor-pointer transition-all duration-300 ${
                filter === type
                  ? "bg-[#1C1C1C] text-white"
                  : "bg-[#F5F3EF] text-[#666] hover:bg-[#EAE7E1]"
              }`}
            >
              {type}
            </button>
          ))}
        </motion.div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          <AnimatePresence mode="popLayout">
            {filtered.map((property, index) => (
              <PropertyCard key={property.id} property={property} index={index} />
            ))}
          </AnimatePresence>
        </div>
      </div>
    </section>
  );
}
