import { useRef } from "react";
import { Link } from "react-router-dom";
import { motion, useInView } from "framer-motion";
import { dronePackages } from "../../../mocks/properties";

export default function DronePackages() {
  const ref = useRef(null);
  const inView = useInView(ref, { once: true, margin: "-100px" });

  return (
    <section ref={ref} className="py-24 bg-[#FAF9F7]">
      <div className="max-w-7xl mx-auto px-6 lg:px-10">
        <motion.div
          className="text-center mb-16"
          initial={{ opacity: 0, y: 30 }}
          animate={inView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.7 }}
        >
          <span className="text-[#C9A84C] text-xs font-semibold tracking-widest uppercase">Pricing</span>
          <h2 className="text-4xl lg:text-5xl font-bold text-[#1C1C1C] mt-3 mb-5" style={{ fontFamily: "'Cormorant Garant', serif" }}>
            Drone Shoot Packages
          </h2>
          <p className="text-[#666] text-base max-w-xl mx-auto">
            Powered by DJI Mavic 3 Pro. Choose the package that fits your property and budget.
          </p>
        </motion.div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 max-w-5xl mx-auto">
          {dronePackages.map((pkg, index) => (
            <motion.div
              key={pkg.id}
              className={`relative rounded-2xl p-8 ${
                pkg.popular ? "bg-[#1C1C1C] text-white" : "bg-white"
              }`}
              initial={{ opacity: 0, y: 40 }}
              animate={inView ? { opacity: 1, y: 0 } : {}}
              transition={{ duration: 0.6, delay: index * 0.15 }}
              whileHover={{ y: -6 }}
            >
              {pkg.popular && (
                <div className="absolute -top-3 left-1/2 -translate-x-1/2">
                  <span className="px-4 py-1 bg-[#C9A84C] text-white text-xs font-bold rounded-full whitespace-nowrap">
                    Most Popular
                  </span>
                </div>
              )}

              <div className="mb-6">
                <div className={`w-10 h-10 flex items-center justify-center rounded-xl mb-4 ${
                  pkg.popular ? "bg-[#C9A84C]/20" : "bg-[#F5F3EF]"
                }`}>
                  <i className={`ri-flight-takeoff-line ${pkg.popular ? "text-[#C9A84C]" : "text-[#1C1C1C]"} text-lg`} />
                </div>
                <h3 className={`text-xl font-bold mb-1 ${pkg.popular ? "text-white" : "text-[#1C1C1C]"}`}>
                  {pkg.name}
                </h3>
                <div className={`text-3xl font-bold ${pkg.popular ? "text-[#C9A84C]" : "text-[#1C1C1C]"}`} style={{ fontFamily: "'Cormorant Garant', serif" }}>
                  {pkg.price}
                </div>
                <span className={`text-xs ${pkg.popular ? "text-white/50" : "text-[#888]"}`}>per shoot</span>
              </div>

              <ul className="space-y-3 mb-8">
                {pkg.features.map((feature) => (
                  <li key={feature} className="flex items-center gap-2.5">
                    <div className="w-4 h-4 flex items-center justify-center flex-shrink-0">
                      <i className="ri-check-line text-xs text-[#C9A84C]" />
                    </div>
                    <span className={`text-sm ${pkg.popular ? "text-white/70" : "text-[#666]"}`}>{feature}</span>
                  </li>
                ))}
              </ul>

              <Link
                to="/reservation"
                className={`block text-center py-3 rounded-xl text-sm font-semibold transition-all duration-300 cursor-pointer whitespace-nowrap ${
                  pkg.popular
                    ? "bg-[#C9A84C] text-white hover:bg-[#b8963e]"
                    : "bg-[#F5F3EF] text-[#1C1C1C] hover:bg-[#1C1C1C] hover:text-white"
                }`}
              >
                Book This Package
              </Link>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
}
