import { useState, useEffect } from "react";
import { Link, useLocation } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";

const navLinks = [
  { label: "Home", path: "/" },
  { label: "Map", path: "/map" },
  { label: "Book a Shoot", path: "/reservation" },
  { label: "Contact", path: "/contact" },
];

export default function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 40);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  useEffect(() => {
    setMobileOpen(false);
  }, [location]);

  return (
    <motion.nav
      className={`fixed top-0 left-0 w-full z-50 transition-all duration-500 ${
        scrolled ? "bg-white/95 backdrop-blur-md shadow-sm" : "bg-transparent"
      }`}
      initial={{ y: -80 }}
      animate={{ y: 0 }}
      transition={{ duration: 0.7, ease: "easeOut" }}
    >
      <div className="max-w-7xl mx-auto px-6 lg:px-10 flex items-center justify-between h-20">
        <div className="flex items-center gap-4">
          <a
            href="/index.html"
            className={`hidden md:flex items-center gap-1.5 text-xs font-semibold tracking-widest uppercase transition-colors duration-300 ${scrolled ? "text-[#888] hover:text-[#1C1C1C]" : "text-white/60 hover:text-white"}`}
          >
            ← Midpoint Creative
          </a>
          <Link to="/" className="flex items-center gap-3 cursor-pointer whitespace-nowrap">
            <img
              src="https://public.readdy.ai/ai/img_res/55c41d54-71f0-46ac-ba31-6b88e066bcef.png"
              alt="DroneEstate LA Logo"
              className="h-12 w-auto object-contain"
            />
          </Link>
        </div>

        <div className="hidden md:flex items-center gap-8">
          {navLinks.map((link) => {
            const isActive = location.pathname === link.path;
            return (
              <Link
                key={link.path}
                to={link.path}
                className={`relative text-sm font-medium tracking-wide transition-all duration-300 cursor-pointer whitespace-nowrap ${
                  scrolled
                    ? isActive ? "text-[#C9A84C]" : "text-[#1C1C1C] hover:text-[#C9A84C]"
                    : isActive ? "text-[#C9A84C]" : "text-white/90 hover:text-white"
                }`}
              >
                {link.label}
                {isActive && (
                  <motion.div
                    className="absolute -bottom-1 left-0 right-0 h-0.5 bg-[#C9A84C] rounded-full"
                    layoutId="navbar-underline"
                    transition={{ type: "spring", stiffness: 380, damping: 30 }}
                  />
                )}
              </Link>
            );
          })}
        </div>

        <div className="hidden md:flex items-center gap-4">
          <Link
            to="/reservation"
            className="px-5 py-2.5 bg-[#C9A84C] text-white text-sm font-semibold rounded-lg hover:bg-[#b8963e] transition-all duration-300 whitespace-nowrap cursor-pointer"
          >
            Book Drone Shoot
          </Link>
        </div>

        <button
          className="md:hidden w-8 h-8 flex flex-col justify-center items-center gap-1.5 cursor-pointer"
          onClick={() => setMobileOpen(!mobileOpen)}
        >
          <span className={`block w-6 h-0.5 transition-all duration-300 ${scrolled ? "bg-[#1C1C1C]" : "bg-white"} ${mobileOpen ? "rotate-45 translate-y-2" : ""}`} />
          <span className={`block w-6 h-0.5 transition-all duration-300 ${scrolled ? "bg-[#1C1C1C]" : "bg-white"} ${mobileOpen ? "opacity-0" : ""}`} />
          <span className={`block w-6 h-0.5 transition-all duration-300 ${scrolled ? "bg-[#1C1C1C]" : "bg-white"} ${mobileOpen ? "-rotate-45 -translate-y-2" : ""}`} />
        </button>
      </div>

      <AnimatePresence>
        {mobileOpen && (
          <motion.div
            className="md:hidden bg-white border-t border-[#F0EDE8] px-6 py-4"
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: "auto" }}
            exit={{ opacity: 0, height: 0 }}
            transition={{ duration: 0.3 }}
          >
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                className="block py-3 text-sm font-medium text-[#1C1C1C] hover:text-[#C9A84C] transition-colors cursor-pointer"
              >
                {link.label}
              </Link>
            ))}
            <Link
              to="/reservation"
              className="mt-3 block px-5 py-2.5 bg-[#C9A84C] text-white text-sm font-semibold rounded-lg text-center whitespace-nowrap cursor-pointer"
            >
              Book Drone Shoot
            </Link>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.nav>
  );
}
